/** City for a store code; falls back to the raw code when unknown/blank. */
export function cityForStore(storeCode: string | null | undefined): string {
  const code = String(storeCode ?? '').trim();
  if (!code) return '';
  const city = STORE_CITY[code];
  if (!city || city.toLowerCase() === 'city not available') return code;
  return city;
}
